import React, { useEffect, useState } from "react";
import "./AdminDashboard.css";
import { Bar, Pie } from "react-chartjs-2";
import {
  Chart as ChartJS,
  BarElement,
  ArcElement,
  CategoryScale,
  LinearScale,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(
  BarElement,
  ArcElement,
  CategoryScale,
  LinearScale,
  Tooltip,
  Legend
);

const AdminDashboard = () => {
  const [predictions, setPredictions] = useState([]);

  useEffect(() => {
    // Replace with your backend API
    setPredictions([
      {
        email: "raj24@gmail.com",
        role: "Software Engineer",
        location: "Bangalore",
        salary: 75000,
      },
      {
        email: "anita56@yahoo.com",
        role: "Data Scientist",
        location: "Mumbai",
        salary: 100000,
      },
    ]);
  }, []);

  // Bar Chart Data
  const barData = {
    labels: ["<40k", "40-60k", "60-80k", "80-100k", ">100k"],
    datasets: [
      {
        label: "Predictions",
        data: [65, 120, 100, 80, 70],
        backgroundColor: ["#36A2EB", "#6A5ACD", "#FFA07A", "#9370DB", "#1E90FF"],
      },
    ],
  };

  // Pie Chart Data
  const pieData = {
    labels: ["Experienced", "Entry-Level", "Intermediate", "Post-Graduate"],
    datasets: [
      {
        data: [35, 25, 20, 20],
        backgroundColor: ["#4e73df", "#f6c23e", "#1cc88a", "#e74a3b"],
      },
    ],
  };

  return (
    <div className="dashboard-container">
      
      {/* Sidebar */}
      <div className="sidebar">
        <h2>Admin</h2>
        <ul>
          <li>Dashboard</li>
          <li>Manage Users</li>
          <li>Reports</li>
          <li>Settings</li>
        </ul>
      </div>

      {/* Main */}
      <div className="main-content">
        
        {/* Navbar */}
        <div className="navbar">
          <h1>Admin Dashboard</h1>
        </div>

        {/* Cards */}
        <div className="cards">
          <div className="card card1">
            <p>Avg Salary</p>
            <h2>₹68,450</h2>
          </div>
          <div className="card card2">
            <p>Highest Salary</p>
            <h2>₹1,20,000</h2>
          </div>
          <div className="card card3">
            <p>Lowest Salary</p>
            <h2>₹35,000</h2>
          </div>
          <div className="card card4">
            <p>Total Users</p>
            <h2>580</h2>
          </div>
        </div>

        {/* Charts */}
        <div className="charts">
          <div className="chart">
            <h3>Salary Distribution</h3>
            <Bar data={barData} />
          </div>

          <div className="chart">
            <h3>User Demographics</h3>
            <Pie data={pieData} />
          </div>
        </div>

        {/* Table */}
        <div className="table-section">
          <h3>Recent Predictions</h3>
          <table>
            <thead>
              <tr>
                <th>Email</th>
                <th>Job Role</th>
                <th>Location</th>
                <th>Salary</th>
              </tr>
            </thead>
            <tbody>
              {predictions.map((item, index) => (
                <tr key={index}>
                  <td>{item.email}</td>
                  <td>{item.role}</td>
                  <td>{item.location}</td>
                  <td>₹{item.salary}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

      </div>
    </div>
  );
};

export default AdminDashboard;
